null, "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《四季清邁》Four Seasons Chiang Mai 坐落在湄林谷地，被稻田與山巒環繞。這裡的奢華不張揚，而是藏在細節裡：柚木傢俱的紋理、手工編織的床罩、浴室裡泰國香草製成的備品。每間房都有私人陽台面對稻田，清晨薄霧中水牛在田間緩慢移動，彷彿時間靜止。酒店內的泰式烹飪課程由專業主廚教學，從市場採買到料理完成，是深度體驗。Spa 使用蘭納傳統按摩手法，力道專業到位。這不是炫耀性的豪華，而是懂得欣賞細節的人才能體會的質感。", "hotel_class": null, "is_featured": false, "price_range": null, "star_rating": null, "best_seasons": null, "country_code": "TH", "english_name": null, "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_phone": null, "data_verified": false, "display_order": 0, "butler_service": false, "certifications": null, "deleted_reason": null, "description_en": null, "dining_options": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "09ddb7ab-8aa4-49e4-92ce-0bfc6e666b88", "fax": null, "name": "Grandvrio Hotel Beppuwan Wakura", "brand": null, "notes": null, "phone": "0977-66-3111", "awards": null, "images": null, "address": "大分県別府市上人ヶ浜6-2", "city_id": "beppu", "website": null, "category": "飯店 / Hotel", "currency": "USD", "latitude": null, "amenities": null, "is_active": true, "longitude": null, "region_id": null, "address_en": null, "country_id": "japan", "created_at": "2026-03-16T07:42:35.829389+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "facilities": null, "highlights": null, "name_local": "グランヴィリオホテル 別府湾 和藏", "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": null, "hotel_class": "standard", "is_featured": false, "price_range": null, "star_rating": 3, "best_seasons": null, "country_code": "JP", "english_name": "Grandvrio Hotel Bep