ies": null, "highlights": null, "name_local": "メルキュール 京都宮津リゾート 舊皇家", "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": null, "hotel_class": "standard", "is_featured": false, "price_range": null, "star_rating": 3, "best_seasons": null, "country_code": "JP", "english_name": "Mercure Kyoto Miyazu Resort & Spa", "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_phone": "0772-25-1800", "data_verified": false, "display_order": 0, "butler_service": false, "certifications": null, "deleted_reason": null, "description_en": null, "dining_options": null, "group_friendly": true, "internal_notes": "🔹房間撥號前面+7\n🔹晚餐在2樓，酒水喝到飽\n🔹早餐在2樓，7:00開始，人多要排隊，請提早前往，記得帶信封出示房號\n🔹房間自動上鎖，出門記得帶房卡\n🔹房間禁菸，請勿出現香菸相關物品在房間內垃圾桶及桌上，吸煙區在一樓\n🔹溫泉區B1，早上6:00-22:30需帶房卡和大小毛巾，刺青者請勿使用\n泉種是「宮津の湯らゆら温泉，塩化物強塩泉質，針對筋肉痛/神經痛/關節痛有療效」\n🔹無料桌球可以預約，需要的請通知我\n🔹房間冰箱的電源請自行打開\n🔹WiFi的帳號ACCOR，要輸入mail才能使用\n🔹一樓有無料迎賓酒水+點心，入住時間～18:00，21:00～23:00", "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "18bc108b-44be-4819-a71d-be0beb1047d4", "fax": null, "name": "阿蘇ホテル　二番館", "brand": null, "notes": null, "phone": null, "awards": null, "images": null, "address": null, "city_id": "tokyo", "website": null, "category": "飯店 / Hotel", "currency": "USD", "latitude": null, "amenities": null, "is_active": true, "longitude": null, "region_id": null, "address_en": null, "country_id": "japan", "created_at": "2026-03-16T07:42:52.304486+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "facilities": null, "highlights": null, "name_local": "阿蘇ホテル　二番館", "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": null, "hotel_class": "standard", "is_featured": false, "price_range": null, "star_rating": 3, "best_seasons": null, "country_code": "JP", "english_name": "Aso Hotel Annex", "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_phone": null, "data_verified": false, "display_order": 0, "butler_service": false, "certifications": null, "deleted_reason": null, "description_en": null, "dining_options": null, "group_friendly": true, "internal_notes": "房間電話互撥，請先撥2再加房號\n\n鑰匙是金屬鑰匙\n\n門口進入房門，請請使用牆上開關開燈\n\n沒有自動上鎖，出房間請記得將房門鎖好，鑰匙拿在手上再離開\n\n冰箱內無瓶裝水和熱水瓶，1樓備有迎賓飲料室，免費供應飲料，需要裝水的貴賓可以去裝，熱水瓶也可以在此處借用至房間內使用。\n\n房間內禁菸\n吸煙室在1樓吸煙處\n\n大廳樓層在1樓\n\n大浴場在1樓，有露天溫泉，至晚上11：00，早上5：00再開放，男女招牌不會更換\n\n上下2件式浴衣置放在房間內\n小朋友的浴衣可至櫃檯索取\n\n大浴巾和小毛巾請至櫃檯領取後帶去大浴場\n\n房間內沒有牙刷，大浴巾和毛巾等備品，請至櫃檯領取\n\nWIFI 全館都有，有密碼\n\n晚餐在2樓，會席料理\n\n早餐在2樓，自助式\n早餐7：00開始，無餐券\n\n可設定morning call", "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "18ddbb3c-b0f0-47de-8199-14b94ff2b73a", "fax": null, "name": "The Yacht Hotel by DC", "brand": null, "notes": null, "phone": null, "awards": null, "images": null, "address": null, "city_id": "vung-tau", "website": null, "category": "飯店 / Hotel", "currency": "USD", "latitude": null, "amenities": null, "is_active": true, "longitude": null, "region_id": null, "address_en": null, "country_id": "vietnam", "created_at": "2026-03-17T08:23:54.948905+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "facilities": null, "highlights": null, "name_local": null, "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": null, "hotel_class": null, "is_featured": false, "price_range": null, "star_rating": null, "best_seasons": null, "country_code": "VN", "english_name": null, "workspace_id": "aed1bc23-7bbf-4c