。\n\n👽領隊房號：\n☎️房號互撥：直撥\n🔐傳統鑰匙，自動上鎖，遺失手續費1萬円\n\n🌞降雨：%\n🌡️溫度：度(注意防曬）\n\n⏰明天起床時間：6:00\n🚌出發時間：8:00\n     集合地點：大廳G樓\n\n🍞早餐餐廳：G樓（自助餐）07:00\n⭐️自行用餐⭐️不用餐卷\n🍽️晚餐餐廳：G樓（18:00用餐）\n\n💳鑰匙不可遺失，請妥善保管\n🔑明早鑰匙請交還給1樓櫃檯，或給阿霖協助辦理退房。\n\n🛜WIFI\n帳號：SUNPLAZA\n密碼 ：sunplaza3939\n\n👘浴衣：在房間\n     浴衣穿法：左上右下，小孩浴衣，上樓前請櫃檯領取）\n\n♨ 溫泉：G樓 =1樓\n入浴時間：早上6:00-晚上12:00\n  ⭐️從房間帶大小毛巾到浴場，請重複使用並帶回房間。可以穿飯店的浴衣去泡湯，泡15分鐘休10分鐘，⭕️起身前一定要讓心臟超過水面30秒再緩緩起身。盡可能結伴同行。若有大片刺青會被拒絕入浴，敬請見諒。\n\n🚭房間及室內禁菸\n🚬吸煙室G樓電梯前\n⭐️房內抽菸會有高額罰金及損害賠償，即使在外面抽，煙灰、煙蒂也請別帶回房間垃圾桶\n❌禁止開窗　會有蚊蟲\n\n🏪便利商店：飯店出去左邊，走路1分鐘，全家，營業時間07:00-23:00吧\n\n😱溫馨提醒\n⭐️離開房間，請回頭看一眼書桌、衣櫥、冰箱、浴室。\n掉東西第一名：充電器。第二名：化妝包。第三名：耳環首飾類。\n\n⭐️明早大廳G樓電梯口前有行李置物的看板，建議您可以在吃早餐前，就先整理好行李置放，比較不會掉東西。", "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "1fe1f0b3-ee30-42c8-b530-f3c71e754886", "fax": null, "name": "松山東急REI飯店", "brand": null, "notes": null, "phone": "089-913-0109", "awards": null, "images": null, "address": "愛媛縣松山市一番町3-3-1", "city_id": "matsuyama", "website": null, "category": "飯店 / Hotel", "currency": "USD", "latitude": null, "amenities": null, "is_active": true, "longitude": null, "region_id": null, "address_en": null, "country_id": "japan", "created_at": "2026-03-16T07:42:39.102367+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "facilities": null, "highlights": null, "name_local": "松山東急REIホテル", "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": null, "hotel_class": "standard", "is_featured": false, "price_range": null, "star_rating": 3, "best_seasons": null, "country_code": "JP", "english_name": "Matsuyama Tokyu REI Hotel", "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_phone": "089-913-0109", "data_verified": false, "