巾，毛巾需重複使用於1樓挑選適合的浴衣尺寸，腰帶和外套在房間內。\n⭕️泡溫泉15分鐘，休息10分鐘。盡可能結伴同行，吃完飯後40分鐘後再泡。泡完起身時，盡可能讓心臟高於水面30秒左右後再緩緩起身，避免暈厥。\n\n四種不同溫泉泉質：\n硫磺泉、單純硫磺泉\n食鹽泉、酸性鐵泉\n\n🎁賣店：1F 7:00-22:00\n🕹️ 遊戲電玩區：B1F~23:00\n\n🚭全館禁煙🚬 \n吸煙區：戶外、1樓室內、3樓（加熱式）\n⭐️請勿心存僥倖，即使在外面抽，煙灰、煙蒂也請別帶回房間垃圾桶。開放至今，已發生多起，別團團員賠錢事件。\n\n😱溫馨提醒\n⭐️離開房間，請回頭看一眼書桌、衣櫥、冰箱、浴室。\n掉東西第一名：充電器。第二名：化妝包。第三名：耳環首飾類。\n\n⭐️請將明日整天有可能使用的保溫瓶、個人藥品、小外套、行動電源、wifi機放在隨身行李，避免旅途中翻箱倒櫃。\n\n⭐️明早一樓會有出發前行李置物處（）的看板，建議您可以在吃早餐前，就先整理好行李置放，比較不會掉東西。", "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "3b689e92-18d9-467a-b177-fdea5ad0fc2a", "fax": null, "name": "霧島京瓷飯店", "brand": null, "notes": null, "phone": "0995-78-2111", "awards": null, "images": null, "address": "鹿児島県霧島市牧園町高千穂3930", "city_id": "tokyo", "website": null, "category": "飯店 / Hotel", "currency": "USD", "latitude": null, "amenities": null, "is_active": true, "longitude": null, "region_id": null, "address_en": null, "country_id": "japan", "created_at": "2026-03-16T07:42:52.304486+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "facilities": null, "highlights": null, "name_local": "霧島京セラホテル", "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": null, "hotel_class": "standard", "is_featured": false, "price_range": null, "star_rating": 3, "best_seasons": null, "country_code": "JP", "english_name": "Kirishima Kyoraku Hotel", "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_phone": "0995-78-2111", "data_verified": false, "display_order": 0, "butler_service": false, "certifications": null, "deleted_reason": null, "description_en": null, "dining_options": null, "group_friendly": true, "internal_notes": "★霧島京瓷飯店★\n入住「別館」，若要到本館走3樓連絡通路\n領隊房間：653\n🔑房卡遺失罰金11