場\n\n🏪飯店內賣店：營業至21:00\n🏪便利商店：LAWSON,24H,步行約8-10分鐘\n走到鬼怒川車站約15-20分鐘\n\n😱溫馨提醒\n🌟離開房間，請回頭看一眼書桌、衣櫥、冰箱、浴室。\n掉東西第一名：充電器。第二名：化妝包。第三名：耳環首飾類。\n\n🌟請將明日整天有可能使用的保溫瓶、個人藥品、小外套、行動電源、wifi機放在隨身行李，避免旅途中翻箱倒櫃。\n\n🌟明早3樓大廳，會有出發前行李置物的看板，建議您可以在吃早餐前，就先整理好行李置放，比較不會掉東西。", "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "4d83dd40-0ab1-4a71-ae6d-ad5eb4e01927", "fax": null, "name": "Kobe Meriken Park Oriental Hotel", "brand": null, "notes": null, "phone": "078-325-8111", "awards": null, "images": null, "address": "兵庫県神戸市中央区波止場町5-6", "city_id": "kobe", "website": null, "category": "飯店 / Hotel", "currency": "USD", "latitude": null, "amenities": null, "is_active": true, "longitude": null, "region_id": null, "address_en": null, "country_id": "japan", "created_at": "2026-03-16T07:42:37.898421+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "facilities": null, "highlights": null, "name_local": "神戸メリケンパークオリエンタルホテル", "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": null, "hotel_class": "standard", "is_featured": false, "price_range": null, "star_rating": 3, "best_seasons": null, "country_code": "JP", "english_name": "Kobe Meriken Park Oriental Hotel", "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_phone": "078-325-8111", "data_verified": false, "display_order": 0, "butler_service": false, "certifications": null, "deleted_reason": null, "description_en": null, "dining_options": null, "group_friendly": true, "internal_notes": "🔹大廳在3樓\n🔹房間電話，1+房號\n🔹餐廳在3樓，請勿穿拖鞋\n晚餐 17:30~( 統一進場)\n早餐07:00~10:30，請出示房卡房號，人多要排隊，請提早前往\n🔹房間自動上鎖，出門記得帶房卡\n🔹房間禁菸，請勿出現香菸相關物品在房間內垃圾桶及桌上，吸煙區在四樓\n🔹三樓有便利商店到23:00\n🔹wifi密碼在電視畫面顯示中\n🔹大廳有飲料區無料使用\n🔹有料健身房5樓，10:00~18:45，請帶房卡