道三大飯店之一\n望樓野口函館、洞爺乃之風、La Vista 大雪山。全館79間，18間附設溫泉個室\n\n👽領隊房號： \n☎️房號互撥：1+房號\n☎️內線：9\n\n⏰明天叫早時間：\n🚌出發時間： \n🏨飯店一樓集合\n\n🍞早餐餐廳：3樓套餐，07:30（約時間）\n⭐️集合用餐⭐️無餐卷\n\n🌞降雨：%\n🌡️溫度：度\n\n🏨飯店大廳：1F\n🔑明天早上鑰匙請交還給1樓櫃檯，或給領隊協助退房。\n\n🍺冰箱內的啤酒、茶、水無料\n\n📳WIFI密碼\nSSID：Room No.\nPASSWORD：41264126\n\n🚭全館禁煙🚬 吸菸區：1、2樓電梯右側吸菸區\n⭐️請勿心存僥倖，即使在外面抽，煙灰、煙蒂也請別帶回房間垃圾桶。開放至今，已發生多起，別團團員賠錢事件。\n\n♨️浴場：13樓，使用時間15:00-隔日11:00\n無需帶毛巾，人去就行。\n⭕️泡溫泉15分鐘，休息10分鐘。盡可能結伴同行，吃完飯後40分鐘後再泡。泡完起身時，盡可能讓心臟高於水面30秒左右後再緩緩起身，避免暈厥。\n\n🏬賣店：1樓，08:00-11:00，15:00-21:00\n\n🏪便利商店：出門左邊1分鐘LAWSON ,24H\n\n😱溫馨提醒\n⭐️離開房間，請回頭看一眼書桌、衣櫥、冰箱、浴室。\n掉東西第一名：充電器。第二名：化妝包。第三名：耳環首飾類。\n\n⭐️飯店不肯，所以沒有行李置物處，建議用早餐前整理好，比較不會掉東西。如果想放，飯店說可以隨便找個空位自行置放。", "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "59c6417f-d640-4c92-bafc-8b791988379d", "fax": null, "name": "虹夕諾雅 飛鳥", "brand": "星野集團 - 虹夕諾雅", "notes": null, "phone": null, "awards": null, "images": null, "address": null, "city_id": "nara", "website": null, "category": "奢華度假村", "currency": "USD", "latitude": null, "amenities": null, "is_active": true, "longitude": null, "region_id": null, "address_en": null, "country_id": "japan", "created_at": "2026-04-04T11:39:08.694+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "facilities": null, "highlights": null, "name_local": null, "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": null, "hotel_class": "頂級奢華", "is_featured": true, "price_range": null, "star_rating": 5, "best_seasons": null, "country_code": "JP", "english_name": "Hoshinoya Asuka", "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_phone": null, "data_verified": false, "display_order": 0, "butler_service": false, "certifications": null, "deleted_re