使用喲！\n\n浴衣穿法，右下左上，請勿穿相反喲！\n\n房間有牙膏牙刷，其他一次性使用物品，在2樓大廳，有需要的貴賓請自取\n\n只要飯店大廳wifi 可以直接連，不用密碼\n\n房間wifi id、密碼，在房內案內書裡有標示\n\n飯店房內全面禁煙，有抽菸的貴賓，需請移駕到1、2、3樓吸煙室抽煙，房內不能抽喲！會被罰錢喲！\n\n明天8：30出發\n請在之前於2樓大廳集合喲！\n\n會請飯店設置行李置放區在2樓大廳（百威旅遊  8：30出發  阿琇），可先寄放行李後，再去吃早餐喲！\n\n飯店人手不足，沒有提供早call服務，請各位貴賓自己手機要設個鬧鐘喲！", "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "5ce99d35-6483-46c8-b5dc-243ee9b9ea14", "fax": null, "name": "曼谷嘉佩樂酒店", "brand": "Capella", "notes": null, "phone": null, "awards": null, "images": null, "address": null, "city_id": "bangkok", "website": null, "category": "city", "currency": "USD", "latitude": null, "amenities": null, "is_active": true, "longitude": null, "region_id": null, "address_en": null, "country_id": "thailand", "created_at": "2025-12-17T15:12:39.090728+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "facilities": {"bar": true, "gym": true, "spa": true, "pool": true, "butler": true, "concierge": true, "restaurant": true}, "highlights": ["2024世界最佳酒店第一名", "昭披耶河畔", "私人別墅", "Cote by Mauro Colagreco 餐廳"], "name_local": null, "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "2024年世界50最佳酒店第一名。位於昭披耶河畔，101間客房與別墅，提供絕美河景。", "hotel_class": "ultra-luxury", "is_featured": true, "price_range": "5", "star_rating": 5, "best_seasons": null, "country_code": "TH", "english_name": "Capella Bangkok", "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_phone": null, "data_verified": false, "display_order": 40, "butler_service": false, "certifications": null, "deleted_reason": null, "description_en": null, "dining_options": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "booking_contact": 