n📳WIFI密碼\nSSID：YKH\n密碼：kokusai345\n\n🚭全館禁煙🚬 吸菸區：吸煙處位餐廳旁1樓，所有客房皆為禁菸房，若抽煙被發現會有清潔費產生。\n⭐️請勿心存僥倖，即使在外面抽，煙灰、煙蒂也請別帶回房間垃圾桶。開放至今，已發生多起，別團團員賠錢事件。\n\n🏪便利商店：出大門右轉，大馬路左轉直走7-11，走路約4分鐘。\n\n😱溫馨提醒\n⭐️離開房間，請回頭看一眼書桌、衣櫥、冰箱、浴室。\n掉東西第一名：充電器。第二名：化妝包。第三名：耳環首飾類。\n\n⭐️明早一樓入口處會有出發前行李置物處的看板，建議您可以在吃早餐前，就先整理好行李置放，比較不會掉東西。\n\n⭐️一整天有可能會到的東西，藥品、外套、雨具、行動電源，請先從行李箱內拿出來，避免路上翻箱倒櫃。", "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "648b1732-16e9-42cd-a575-def970b8411d", "fax": null, "name": "界 Anjin", "brand": "星野集團 - 界", "notes": null, "phone": null, "awards": null, "images": null, "address": null, "city_id": "tokyo", "website": null, "category": "精品溫泉旅館", "currency": "USD", "latitude": null, "amenities": null, "is_active": true, "longitude": null, "region_id": null, "address_en": null, "country_id": "japan", "created_at": "2026-04-04T11:39:10.392+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "facilities": null, "highlights": null, "name_local": null, "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": null, "hotel_class": "高端精品", "is_featured": true, "price_range": null, "star_rating": 4, "best_seasons": null, "country_code": "JP", "english_name": "Kai Anjin", "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_phone": null, "data_verified": false, "display_order": 0, "butler_service": false, "certifications": null, "deleted_reason": null, "description_en": null, "dining_options": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": n