n\n飯店附近亦有：\n\n超市：Plaza Tower Mansion 地下1樓\n\n便利商店：7-Eleven、全家、Lawson 等", "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "8800838b-436f-4c83-b0e8-614d443439dd", "fax": null, "name": "花卷飯店", "brand": null, "notes": null, "phone": "0198-27-2111", "awards": null, "images": null, "address": "岩手県花巻市湯本101-1", "city_id": "tokyo", "website": null, "category": "飯店 / Hotel", "currency": "USD", "latitude": null, "amenities": null, "is_active": true, "longitude": null, "region_id": null, "address_en": null, "country_id": "japan", "created_at": "2026-03-16T07:42:51.037075+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "facilities": null, "highlights": null, "name_local": "花巻温泉", "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": null, "hotel_class": "standard", "is_featured": false, "price_range": null, "star_rating": 3, "best_seasons": null, "country_code": "JP", "english_name": "Hanamaki Onsen", "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_phone": "0198-27-2111", "data_verified": false, "display_order": 0, "butler_service": false, "certifications": null, "deleted_reason": null, "description_en": null, "dining_options": null, "group_friendly": true, "internal_notes": "涵蓋以下三家飯店：\n千秋閣飯店（Hotel Senshukaku）、花卷飯店（Hotel Hanamaki）、紅葉館飯店（Hotel Koyokan）\n\n🔹 千秋閣飯店（Hotel Senshukaku）\nB1：大浴場、芳香療癒（Bellefille）、富士餐廳\n\n1F：櫃台、販賣部、休憩區\n\n2F：西式餐廳「BLANC AILE」、日式料理「千壽」\n\n3F：禮拜堂、婚禮更衣室\n\n4F–11F：客房\n\n12F：頂樓宴會廳「PROSPER」\n\n🔹 花卷飯店（Hotel Hanamaki）\nB1：私人溫泉浴場、遊戲區（桌球、電玩）、卡拉OK、投幣式洗衣房\n\n1F：櫃台、販賣部、休息區\n\n2F：大浴場（露天風呂）、櫻花餐廳、拉麵餐廳\n\n3F–6F：客房\n\n7F：日式餐廳「羽山」\n\n🔹 紅葉館飯店（Hotel Koyokan）\nB1：大浴場（露天風呂）、健身房、芳香療癒（香庵）\n\n1F：櫃台、販賣部、祭典廣場\n\n2F：楓葉餐廳\n\n3F–6F：客房\n\n7F：露天餐廳「FOREST TERRACE」、西式餐廳「L'ERABLE」\n\n\n① 私人溫泉\n地點：花卷飯店 B1\n\n時間：18:00～23:00（最後接待 22:15）\n\n收費：每 45 分鐘 1,800 日圓（最多 5 人）\n\n須至櫃台預約\n\n② 芳香按摩（Belle Fille SPA）\n地點：千秋閣 B1「Belle Fille」\n\n時間：16:00～21:00\n\n服務：身體按摩，請於櫃台預約\n\n③ 久慈琥珀飾品店（Kuji Amber）\n地點：千秋閣 1F\n\n時間：07:30～10:30、18:00～21:30\n\n販售：世界知名久慈琥珀製品，包含藍琥珀\n\n④ 南部鐵器與地酒店\n地點：溫泉街附近\n\n時間：15:00～17:00\n\n販售：傳統南部鐵器與地酒（酒品試飲）\n\n⑤ 拉麵酒場\n地點：花卷飯店 2F\n\n時間：18:00～23:00（最後點餐 22:30）\n\n提供：拉麵、丼飯、小菜等\n\n⑥ 鶴羽藥妝店（鶴羽ドラッグ）\n地點：花卷飯店正門\n\n時間：14:00～22:00\n\n提供：藥品、美妝、生活用品等\n\n⑦ 投幣式洗衣房\n地點：花卷飯店 B1\n\n時間：07:00～21:00\n\n投幣使用、洗劑另售，請洽櫃台\n\n⑧ 玫瑰園（Rose Garden）\n地點：飯店外步行可達\n\n開放時間：08:00～17:00（玫瑰季時延長至 21:00）\n\n可依季節賞花、攝影", "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "88d1f432-c070-4674-8311-5eb3b600bc3a", "fax": null, "name": "北京頤和安縵", "brand": "Aman", "notes": null, "phone": null, "awards": null, "images": null, "address": null, "city_id": "beijing", "website": null, "category": "resort", "currency": "USD", "latitude": null, "amenities": null, "is_active": true, "longitude": null, "region_id": null, "address_en": null, "country_id": "china", "created_at": "2025-12-17T15:12:39.090728+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "facilities": {"bar": true, "gym": true, "spa": true, "pool": true, "butler": true, "concierge": true, "restaurant": true}, "highlights": ["頤和園旁絕美位置", "明清建築風格", "皇家般私密體驗", "中式庭園"], "name_local": null, "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "位於頤和園旁，由歷史建築群改建。51間套房融合明清建築風格，提供皇家般的私密體驗。", "hotel_class": "ultra-luxury", "is_featured": true, "price_range": "5", "star_rating": 5, "best_seasons": null, "country_code": "CN", "english_name": "Aman at Summer Palace 