膠囊咖啡\n\n📳WIFI密碼\nID:MarriottBonvoy\n不需密碼直接連接\n\n🚭全館禁煙🚬 吸菸區：4樓，出電梯左轉。\n⭐️請勿心存僥倖，即使在外面抽，煙灰、煙蒂也請別帶回房間垃圾桶。開放至今，已發生多起，別團團員賠錢事件。\n\n🏋️健身房：5樓，24小時，請帶房卡\n\n🏪便利商店：斜對面的三井飯店2樓，Lowson，24小時\n\n😱溫馨提醒\n⭐️離開房間，請回頭看一眼書桌、衣櫥、冰箱、浴室。\n掉東西第一名：充電器。第二名：化妝包。第三名：耳環首飾類。\n\n⭐️明早一樓會有出發前行李置物的看板，建議您可以在吃早餐前，就先整理好行李置放，比較不會掉東西。\n\n⭐️整理行李的時候，請將瓶裝標示容量100cc以上的液體（乳霜、護手霜、人工淚液、泡麵、面膜、飲料etc）、尖銳物品（小刀、指甲剪、食物剪、修眉刀、瑞士刀etc）放入行李箱中。\n\n⭐️打火機、行動電源可以隨身攜帶，不可托運。防風式打火機必須丟棄。\n\n⭐️不可攜帶動植物，種子，生鮮蔬果，肉類入境台灣，機上餐食含肉菜：若未吃完也不可帶下飛機\n\n⭕️表定飛機起飛為日本時間20:40，大約日本時間21:20有機上簡餐，於台灣時間23:20抵達桃園機場第二航廈\n感謝您", "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "91965b81-4de5-457f-bd62-c45844034bc6", "fax": null, "name": "高松東急REI飯店", "brand": null, "notes": null, "phone": "087-821-0109", "awards": null, "images": null, "address": "香川県高松市錦町1-15-1", "city_id": "takamatsu", "website": null, "category": "飯店 / Hotel", "currency": "USD", "latitude": null, "amenities": null, "is_active": true, "longitude": null, "region_id": null, "address_en": null, "country_id": "japan", "created_at": "2026-03-16T07:42:42.083116+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "facilities": null, "highlights": null, "name_local": "高松東急REIホテル", "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": null, "hotel_class": "standard", "is_featured": false, "price_range": null, "star_rating": 3, "best_seasons": null, "country_code": "JP", "english_name": "Takamatsu Tokyu REI Hotel", "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_phone": "087-821-0109", "data_verified": false, "display_order": 0, "butler_service": false, "certifications": null, "deleted_reason": null, "description_en": null, "dining_options":