lable": false, "has_michelin_restaurant": false}, {"id": "97f933ea-91f8-4809-adbf-4e07c2a49d12", "fax": null, "name": "函館川之湯溫泉 海與灯", "brand": null, "notes": null, "phone": "0138-84-2111", "awards": null, "images": null, "address": "北海道函館市湯川町3丁目11番1号", "city_id": "tokyo", "website": null, "category": "飯店 / Hotel", "currency": "USD", "latitude": null, "amenities": null, "is_active": true, "longitude": null, "region_id": null, "address_en": null, "country_id": "japan", "created_at": "2026-03-16T07:42:46.764834+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "facilities": null, "highlights": null, "name_local": "函館 川の湯温泉 海と灯", "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": null, "hotel_class": "standard", "is_featured": false, "price_range": null, "star_rating": 3, "best_seasons": null, "country_code": "JP", "english_name": "Hakodate Kawa no Yu Onsen Umi to Akari", "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_phone": "0138-84-2111", "data_verified": false, "display_order": 0, "butler_service": false, "certifications": null, "deleted_reason": null, "description_en": null, "dining_options": null, "group_friendly": true, "internal_notes": "HAKODATE YUNOKAWA ONSEN UMI TO AKARI / HEWITT RESORT\n\n\n👽領隊房號：1103\n☎️房號互撥：2+房間號碼\n\n⏰明天叫早時間：\n🚌出發時間：\n\n🇯🇵明天降雨：%\n🌡️溫度：度\n\n🍞早餐餐廳：2樓，06:30\n⭐️自行用餐，憑餐卷用餐\n\n🏨飯店大廳：1F\n🛗進電梯需感應房卡，房卡只能去自己的樓層。\n🔑房間鑰匙：請妥善保管鑰匙，明早鑰匙請交還給一樓櫃檯，或給領隊協助退房。\n\n📳 📳WIFI密碼 ： \n名稱：HHRHakodate\n密碼：HHRH5390\n\n🎁賣店：1F \n7:30-9:00\n\n♨️溫泉：12樓\n下午14:00-01:00，早上05:00-10:00\n泡湯盡可能結伴同行，泡15分鐘休息10分鐘。吃完飯後40分鐘後再泡。\n‼️如有飲酒請2小時後再泡，請注意安全。\n⭕️起身時一定要讓心臟超過水面30秒以上再緩緩起身，避免暈厥。\n\n🚭全館禁煙🚬 吸菸區：1樓、2樓、12樓。\n\n🏪便利商店：出門右轉5分鐘，LAWSON，24H。\n\n😱溫馨提醒\n⭐️離開房間，請回頭看一眼書桌、衣櫥、冰箱、浴室。\n掉東西第一名：充電器。第二名：化妝包。第三名：耳環首飾類。\n\n⭐️請將明日白天有可能使用的保溫瓶、隨身小物、外套、行動電源、雨具裝在隨身行李，放置巴士位置上。\n\n⭐️明早一樓會有出發前行李置物處的看板，建議您可以在吃早餐前，就先整理好行李置放，比較不會掉東西。\n\n湯之川溫泉的歷史\n治愈藩主的湯之川溫泉\n1653年（承應2年），第九代松前藩主-高廣（乳名 千勝丸）疾病纏身，病情一天比一天惡化。\n某天晚上其母清涼院夢到「如果去松前城以東的溫泉，無論是任何病都可治癒」，於是便讓千勝丸到松前城以東的溫泉養病，不久千勝丸便大病痊癒。\n後來松前藩為了表示感謝，就重建了藥師堂並供奉上黃金製的藥師如來像及鱷嘴鈴作為答謝。\n據說這就是湯之川溫泉的起源。", "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "980203cf-904c-4bf9-8a6b-ca04727366d2", "fax": null, "name": "RISONARE 熱海", "brand": "星野集團 - RISONARE", "notes": null, "phone": null, "awards": null, "images": null, "address": null, "city_id": "tokyo", "website": null, "category": "精品溫泉旅館", "currency": "USD", "latitude": null, "amenities": null, "is_active": true, "longitude": null, "region_id": null, "address_en": null, "country_id": "japan", "created_at": "2026-04-04T11:39:12.68+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "facilities": null, "highlights": null, "name_local": null, "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": null, "hotel_class": "高端精品", "is_featured": true, "price_range": null, "star_rating": 4, "best_seasons": null, "country_code": "JP", "english_name": "RISONARE Atami", "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_phone": null, "data_verified": false, "display_order": 0, "butler_service": false, "certifications": null, "deleted_reason": null, "description_en": null, "dining_options": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "9868276f-2a06-4ef8-b280-e8be1a1640b6", "fax": null, "name": "Y's Hotel 旭川站前", "brand": null, "notes"