自助餐 6：30 ~\n2樓『朝日之間』，憑鑰匙自由入場，座位自由席\n\n飯店wifi ID：aishinwifi\n\n密碼：aishinwifi\n\n明日8：20  一樓出發\n\n早call是6：20，建議各位貴賓自己手機也要設個鬧鐘，以防飯店電話聲音太小叫不醒您喲！\n\n飯店館內全面禁煙，有抽菸的貴賓，需請移駕到1樓吸煙區抽煙，房內不能抽喲！會被罰錢喲！\n\n大浴場  3樓\n ~03：00為止（最後入場02：00）\n隔天早上5：00開始又可以泡喲！\n\n庭園繩文露天溫泉  3樓\n~22：00為止（最後入場21：00）\n隔天早上5：00開始又可以泡喲！\n\n毛巾在房內，請攜帶至大浴場使用，使用完畢請帶回房間\n\n浴衣和拖鞋，館內、餐廳皆可使用喲！\n\n隔天早上溫泉的男女湯場地會互換，請小心不要跑錯地方喲！\n\n浴衣房間有放M尺寸，若需其他尺寸的話，在各樓層電梯旁，請依照身高拿取適合您的尺寸\n腰帶在衣櫃裡", "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "9a9d3cf2-f295-4109-9504-8d3acc360f11", "fax": null, "name": "ANA假日宮崎", "brand": null, "notes": null, "phone": "0985-32-1361", "awards": null, "images": null, "address": "〒880-0805 宮崎県宮崎市宮崎駅東１丁目2番地2", "city_id": "miyazaki", "website": null, "category": "飯店 / Hotel", "currency": "USD", "latitude": null, "amenities": null, "is_active": true, "longitude": null, "region_id": null, "address_en": null, "country_id": "japan", "created_at": "2026-03-16T07:42:34.679036+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "facilities": null, "highlights": null, "name_local": "ANAホリデイ・イン宮崎", "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": null, "hotel_class": "standard", "is_featured": false, "price_range": null, "star_rating": 3, "best_seasons": null, "country_code": "JP", "english_name": "ANA Holiday Inn Miyazaki", "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_phone": "0985-32-1361", "data_verified": false, "display_order": 0, "butler_service": false, "certifications": null, "deleted_reason": null, "description_en": null, "dining_options": null, "group_friendly": true, "internal_notes": "★★宮崎ANA假日飯店★\n⏰起床時間：      （太早太晚請自行設定）\n🚌出發時間：\n（直接到1