ties": null, "highlights": null, "name_local": "御宿 野乃 松江", "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": null, "hotel_class": "standard", "is_featured": false, "price_range": null, "star_rating": 3, "best_seasons": null, "country_code": "JP", "english_name": "Onyado Nono Matsue Hotel", "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_phone": "0852-28-5489", "data_verified": false, "display_order": 0, "butler_service": false, "certifications": null, "deleted_reason": null, "description_en": null, "dining_options": null, "group_friendly": true, "internal_notes": "御宿野乃松江溫泉飯店注意事項\n\n房間互撥  2+房號（阿琇 209 ）\n\n2樓 餐廳有提供免費醬油拉麵    21：30~23：00\n\n早餐   自助餐 2樓   \n6：15~報房號入場即可\n                   \n大浴場 11樓\n15：00~隔天10：00為止\n\n女湯，須輸入密碼才能入場\n男湯，刷房卡即可入場\n\n15:00~25:00有提供免費冰棒\n05：00~10：00有提供免費乳酸菌飲料\n\n大小毛巾在房內，請攜帶至大浴場使用，使用完畢請帶回房間\n\n浴衣和拖鞋館內、餐廳皆可來回使用\n\n浴衣穿法右下左上，切勿相反喲！\n\n抽煙請到1、7、11樓 吸煙室，切勿在房內抽煙，會被罰錢喲！\n\n自動販賣機在1、7、11樓\n製冰機在7、11樓\n漫畫閱讀區 11樓\n免費按摩椅  11樓\n\n飯店WIFI ID：ONYADONONO\n密碼：onyado1234\n\n明日8：00出發，1樓集合\n7：50開始陸續上行李喲！\n\n已請飯店明早在1樓櫃檯附近設置行李置放區（百威旅遊  8：00出發  阿琇），可寄放行李後，再去用早餐喲！\n\n早call是6點，建議各位貴賓自己手機也要設個鬧鐘，以防飯店電話聲音太小叫不醒您喲！\n\n各位貴賓，冰箱的水、小點心是迎賓禮物，可以免費享用喲！", "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "b29a6611-3065-404e-b2d2-8f72fa2d0fa9", "fax": null, "name": "Route Inn 飛驒", "brand": null, "notes": null, "phone": "0577-36-8888", "awards": null, "images": null, "address": "岐阜県高山市山田町317-1", "city_id": "takayama", "website": null, "category": "飯店 / Hotel", "currency": "USD", "latitude": null, "amenities": null, "is_active": true, "longitude": null, "region_id": null, "address_en": null, "country_id": "japan", "created_at": "2026-03-