eleted_by": null, "facilities": null, "highlights": null, "name_local": "雫石プリンスホテル", "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": null, "hotel_class": "standard", "is_featured": false, "price_range": null, "star_rating": 3, "best_seasons": null, "country_code": "JP", "english_name": "Shizukuishi Prince Hotel", "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_phone": "019-693-1111", "data_verified": false, "display_order": 0, "butler_service": false, "certifications": null, "deleted_reason": null, "description_en": null, "dining_options": null, "group_friendly": true, "internal_notes": "雫石王子飯店 ㄋㄚˇ\n⭕️晚餐2樓17:45自由入場，不需要餐券，拿鑰匙入場即可。最晚入場20:00。\n❌不可穿浴衣，拖鞋到餐廳用餐\n\n👽領隊房號：\n☎️房號互撥：8+房號\n\n🌞降雨：%\n🌡️溫度：度\n\n⏰明天叫早時間：\n🚌出發時間：\n\n🍞早餐餐廳：2樓（自助餐），07:00\n⭐️自行用餐⭐️不需餐卷，拿房間鑰匙即可。\n\n❌不可穿浴衣，拖鞋到餐廳用餐\n\n🛜WIFI\nSSID：PRINCE-HOTEL\n密碼：welcomeph\n\n🚭全室禁煙🚬 \n吸煙區：電梯出門左前方。\n⭐️請勿心存僥倖，即使在外面抽，煙灰、煙蒂也請別帶回房間垃圾桶。開放至今，已發生多起，別團團員賠錢事件。\n\n♨ 溫泉：B1（電梯無法直達，1樓電梯出來左轉，就會看到）\n入浴時間：05:00-24:00（最後入埸23:00）\n👘房間浴衣尺寸目前是M，如果需要大小尺寸可以在一樓櫃檯旁領取～\n🧊冰塊：1樓賣店販賣，2樓餐廳有時候可以免費拿到。\n\n因應環保♻️，房間內的備品～除了牙刷以外的梳子等等～如果需要可以在櫃檯旁自行取用～\n\n星空展望（另外付費）\n有三個時段可以上山，買票不分時段，7:30在櫃檯賣票，上山約7分鐘，8:45開始做星空導覽。導覽一次約20分鐘。結束後再下山。可以在櫃檯買躺椅1100日幣。山頂也可以租借，但可能數量有限不夠。", "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "bc2b47af-9932-4067-9b3c-4c33bef4c519", "fax": null, "name": "金澤凱悅尚萃酒店", "brand": null, "notes": null, "phone": "076-256-1234", "awards": null, "images": null, "address": "石川県金沢市広岡1-5-2", "city_id": "tokyo", "website": null, "category": "飯店 / Hotel", "currency": "USD", "latitude": null, "amenities": null, "is_active": true, "longitude": null, "region_id": null, "address_en": null, "country_id": "jap