e, "internal_notes": null, "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "d82975f9-c50a-4d1f-9b89-7c4bd6fed207", "fax": null, "name": "虹夕諾雅 東京", "brand": "星野集團 - 虹夕諾雅", "notes": null, "phone": null, "awards": null, "images": null, "address": null, "city_id": "tokyo", "website": "https://hoshinoya.com/tokyo/", "category": "都市奢華旅館", "currency": "USD", "latitude": null, "amenities": null, "is_active": true, "longitude": null, "region_id": null, "address_en": null, "country_id": "japan", "created_at": "2026-04-04T11:26:20.966+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "facilities": ["溫泉", "懷石餐廳", "Spa", "茶室"], "highlights": ["都市旅館", "頂樓溫泉", "懷石料理", "東京夜景"], "name_local": null, "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "《虹夕諾雅 東京》將傳統日式旅館概念移植到都市高樓。17層塔狀建築，84間客房，每層只有6間房。榻榻米客房配備現代設施，頂樓溫泉可俯瞰東京夜景。餐廳供應懷石料理，食材每日從築地市場採購。這裡證明：即使在東京都心，依然可以創造出遠離塵囂的靜謐空間。虹夕諾雅東京不是西式奢華酒店的翻版，而是日本待客之道的當代詮釋。", "hotel_class": "頂級奢華", "is_featured": true, "price_range": "高端", "star_rating": 5, "best_seasons": null, "country_code": "JP", "english_name": "Hoshinoya Tokyo", "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_phone": null, "data_verified": false, "display_order": 0, "butler_service": false, "certifications": null, "deleted_reason": null, "description_en": null, "dining_options": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "d892c949-34d3-4609-86c7-ed4886020d42", "fax": null, "name": "札幌萬怡酒店", "brand": null, "notes": null, "phone": "011-200-8111", "awards": null, "images": null, "address": "日本, 〒060-0061 北海道札幌市中央区南１条西２丁目１１", "city_id": "sapporo", "website": null, "category": "飯店 / Hotel", "currency": "USD", "latitude": null, "amenities": null, "is_active": true, "longitude": null, "region_id": null, "address_en": null, "country_id": "japan", "created_at": "2026-03-16T07:42:35.229524+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "facilities": null, "highlights": null, "name_local": "コートヤード・バイ・マリオット札幌", "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": null, "hotel_class": "standard", "is_featured": false, "price_range": null, "star_rating": 3, "best_seasons": null, "country_code": "JP", "english_name": "Courtyard by Marriott Sapporo", "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_phone": "011-200-8111", "data_verified": false, "display_order": 0, "butler_service": false, "certifications": null, "deleted_reason": null, "description_en": null, "dining_options": null, "group_friendly": true, "internal_notes": "COURTYARD BY MARRIOTT SAPPORO\n\n⭕️3連泊為響應環保，飯店設定為不清掃。有需要微輕掃，請前一天告訴領隊。需要微清掃，也請將貴重物品鎖進行李箱中。\n\n👽領隊房號：\n☎️房對房: 7+房號\n⏰起床時間：\n🚌出發時間：\n⭐️飯店大廳：1樓\n⭐️房卡只有一張，女生另給白色溫泉卡片。\n\n🌞降雨雪❄️：20-50%\n🌡️溫度：1-8度　\n\n🍞早餐餐廳：有人數份餐券，沒有壓日期。\n      2樓 06:30～10:30，最後入場10:00。\n🔺可能需要候位，建議提早前往用餐\n\n⭐️冰箱上的水及咖啡皆為無料\n\n📳WIFI：信封裡面有使用說明，沒有密碼，進去後按CONNECT\n\n♨️大浴場：2樓，06:00～24:00\n請記得帶房卡，女生的要帶白色卡片\n大小毛巾都在房間裡面，記得攜帶到浴場。請自帶大小毛巾入場，需重複使用。泡15分鐘休息10分鐘，餐後40分鐘後再泡，儘可能結伴同行。⭕️起身那一刻，絕對要讓心臟超過水面30秒再緩緩起身。\n\n🏋️健身房：2樓24小時\n18歲以下不能進去要穿運動服裝", "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "d8b930c7-5218-409c-a814-aab56e323a85", "fax": null, "name": "箱根溫泉旅館", "brand": null, "notes": null, "phone": null, "awards": null, "images": ["https://pfqvdacxowpgfamuvnsn.supabase.co/storage/v1/object/public/attractions/japan/5ea45b24-307c-4a6d-b0e9-cfc2340311fd-1.jpeg"], "address": null, "city_id": "hakone", "website": null, "category": "飯店 / Hotel", "currency": "USD", "latitude": 35.2325, "amenities": null, "is_active": true, "longitude": 139.1069, "region_id": "jp_kanto", "address_en": null, "country_id": "japan", "created_at": "2026-04-06T23:22:25.67235+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "facilities": null, "highlights": null, "name_local": null, "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": "箱根溫泉旅館，箱根有多處溫泉區，強羅、仙石原、湯本各有特色。傳統日式旅館提供一泊二食、溫泉、懷石料理。露天風呂、私人湯屋、客房附溫泉都有。這是體驗日本溫泉文化的最佳選擇，也是箱根旅遊核心體驗。房價每晚2-10萬日圓，建議提前預約。推薦旅館：強羅花壇、箱根吟遊、界箱根。", "hotel_class": null, "is_featured": false, "price_range": null, "star_rating": null, "best_seasons": null, "country_code": "JP", "english_name": "Hakone Ryokan", "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_phone": null, "data_verified": false, "display_order": 0, "butler_service": false, "certifications": null, "deleted_reason": null, "description_en": null, "dining_options": null, "group_friendly": true, "internal_notes": null, "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "d8da3c7f-2aad-4a9c-adf0-ca3b5f31f395", "fax": null, "name": "OMO3 淺草", "brand": "星野集團 - OMO", "notes": null, "phone": null, "awards": null, "images": null, "address": null, "city_id": "tokyo", "website": null, "category": "都市精