ge": null, "star_rating": 3, "best_seasons": null, "country_code": "JP", "english_name": "Karuizawa Marriott Hotel", "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_phone": "0267-45-6000", "data_verified": false, "display_order": 0, "butler_service": false, "certifications": null, "deleted_reason": null, "description_en": null, "dining_options": null, "group_friendly": true, "internal_notes": "⭕️ 浴衣穿法：衣領開襟左上右下，只能穿去浴場，❌餐廳與大廳不行❌。\n⭕️進去的地方叫做大廳Lobby，1樓其實是2樓。\n\n👽領隊房間：\n☎️房號互撥： 直撥\n\n⏰明天叫早時間：\n🚌出發時間：\n\n🌞明天降雨：%\n🌡️明天溫度：度\n\n🏨飯店大廳：大廳Lobby集合\n\n🍞早餐餐廳：入門左側，大廳Lobby（自助餐）\n      6:45開始用餐\n⭐️有餐卷，自行用餐。\n\n🛜WI-FI\nSSID：MarriottBonvoy\n無需密碼直接連結。\n\n♨️溫泉大浴場:(小瀨溫泉）\nB1 露天浴場\n時間：早上5:00-10:00\n            下午15:00-24:00\n⭐️大小毛巾自己從房間裡帶過去\n（小毛巾可以下湯，大毛巾請放在旁邊籃子或櫃子裡），泡湯盡可能結伴同行，泡15分鐘休息10分鐘。請注意安全。⭕️站起來前，請讓心臟超過水面30-60秒，再緩緩起身。\n\n🚭全館禁煙🚬 吸菸室：1 樓大廳。\n🌟請勿心存僥倖，即使在外面抽，煙灰、煙蒂也請別帶回房間垃圾桶。開放至今，已發生多起，別團團員賠錢事件。\n\n😱溫馨提醒\n🌟離開房間，請回頭看一眼書桌、衣櫥、冰箱、浴室。\n掉東西第一名：掛在衣櫃的衣服，充電器。第二名：化妝包。第三名：耳環首飾類。\n\n🌟明早Lobby大廳會有出發前行李置的看板，建議您可以在吃早餐前，就先整理好行李置放，比較不會掉東西。", "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "dcbe907a-b88e-482f-9c0b-e90998ddd3ae", "fax": null, "name": "熊本日航飯店", "brand": null, "notes": null, "phone": "096-211-2211", "awards": null, "images": null, "address": "熊本県熊本市中央区桜町2-1", "city_id": "kumamoto", "website": null, "category": "飯店 / Hotel", "currency": "USD", "latitude": null, "amenities": null, "is_active": true, "longitude": null, "region_id": null, "address_en": null, "country_id": "japan", "created_at": "2026-03-16T07:42:39.102367+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "facilities": null, "highlights": null, "name_local": "ホテル日航熊本", "room_types": null, "updated_at": "2026-04-15T21:1