e, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "eedbb0d5-834c-4bae-a0d4-ebb212a3c34e", "fax": null, "name": "舞濱歐亞ANNEX飯店", "brand": null, "notes": null, "phone": "047-350-8555", "awards": null, "images": null, "address": "千葉県浦安市舞浜2-50", "city_id": "tokyo", "website": null, "category": "飯店 / Hotel", "currency": "USD", "latitude": null, "amenities": null, "is_active": true, "longitude": null, "region_id": null, "address_en": null, "country_id": "japan", "created_at": "2026-03-16T07:42:49.089976+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "facilities": null, "highlights": null, "name_local": "ホテル　ユーラシア舞浜　アネックス", "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": null, "hotel_class": "standard", "is_featured": false, "price_range": null, "star_rating": 3, "best_seasons": null, "country_code": "JP", "english_name": "Hotel Eurasia Maihama Annex", "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_phone": "047-350-8555", "data_verified": false, "display_order": 0, "butler_service": false, "certifications": null, "deleted_reason": null, "description_en": null, "dining_options": null, "group_friendly": true, "internal_notes": "HOTEL EURASIA MAIHAMA ANNEX\n\n👽領隊房號：\n☎️房號互撥：❌房間沒有電話\n請用Line聯絡。\n📞電梯口有電話，可以聯絡總機\n\n🇯🇵明天降雨：%\n🌡️溫度 ：度\n\n⏰明天叫早時間：❌請自行設定鬧鐘\n🚌出發時間：\n🏨飯店大廳：大廳1樓集合\n\n🍞早餐餐廳：\n1樓（自助餐）6:30-9:30。（9:00最後入場）\n🌟有餐券，餐卷有分日期。 \n🌟自行用餐。\n🚫不可穿睡衣拖鞋\n❗️6:30-8:00用餐人數較多，請留餘裕的時間用餐。\n\n📳WIFI密碼\nID：EURASIA\nPASSWORD：12345678\n寫在房卡的小信封袋上\n\n🧹連泊如不打掃的貴賓，請將『請勿打擾』的磁鐵貼在門外，垃圾打包好放門口即可。\n🌟需要打掃的貴賓，請不要在床上放任何東西，不然無法整理床鋪。\n\n🔑房卡為感應式卡片（1房2卡，小朋友無），請妥善保管，遺失會索賠¥3000。房間會自動上鎖，房卡請隨身攜帶。\n💡入房插卡才有電\n🌟退房時必須歸還1樓櫃台或交給阿霖協助退房。\n\n🌟1樓 餐廳 ：有提供飲水，及微波爐，請自行取用\n🌟1樓的「備品」卸妝棉、刮鬍刀、梳子、澡球…等盥洗用品等，可以自選三樣，住2晚的情形，可以挑選6樣。 \n🧊製冰機:  2樓/4樓\n\n🚭全館禁煙🚬 \n吸菸室：1樓，餐廳再過去\n🌟請勿心存僥倖，即使在外面抽，煙灰、煙蒂也請別帶回房間垃圾桶。開放至今，已發生多起，別團團員賠錢事件。\n\n🛒小賣店：1樓，（水，零食）5:00-24:00\n\n🏪便利商店：Daily yamazaki，玄關出去到馬路後左轉，遇到第一個馬路右轉，步行約10分鐘\n\n🚌免費接駁車至舞浜車站：\n請注意不要坐錯車，要寫有紅色的ANNEX的巴士。\n\n🌟後天早上1樓大廳櫃檯前，會有出發前行李置物的看板，建議您可以在吃早餐前，就先整理好行李置放，比較不會掉東西。\n\n🛍️後天出發時請將白天有可能使用的保溫瓶，隨身小物，保暖衣物，保暖用品，裝在隨身行李，放置巴士位置上。避免在行程中翻箱倒櫃。\n\n😱溫馨提醒\n🌟連住兩天很容易掉東西。離開房間時，請回頭看一眼書桌、衣櫥、冰箱、浴室。\n掉東西第一名：充電器。第二名：化妝包。第三名：耳環首飾類。", "max_group_size": null, "booking_contact": null, "commission_rate": null, "google_maps_url": null, "airport_transfer": false, "concierge_service": true, "restaurants_count": null, "avg_price_per_night": null, "min_rooms_for_group": null, "group_rate_available": false, "has_michelin_restaurant": false}, {"id": "eff17782-f705-404c-89c0-fee727b327ff", "fax": null, "name": "仙台威斯汀酒店", "brand": null, "notes": null, "phone": "022-722-1234", "awards": null, "images": null, "address": "日本, 〒980-0021 宮城県仙台市青葉区中央１丁目１−１", "city_id": "sendai", "website": null, "category": "飯店 / Hotel", "currency": "USD", "latitude": null, "amenities": null, "is_active": true, "longitude": null, "region_id": null, "address_en": null, "country_id": "japan", "created_at": "2026-03-16T07:42:38.507353+00:00", "created_by": null, "deleted_at": null, "deleted_by": null, "facilities": null, "highlights": null, "name_local": "ウェスティンホテル仙台", "room_types": null, "updated_at": "2026-04-15T21:18:09.793607+00:00", "updated_by": null, "description": null, "hotel_class": "standard", "is_featured": false, "price_range": null, "star_rating": 3, "best_seasons": null, "country_code": "JP", "english_name": "The Westin Sendai", "workspace_id": "aed1bc23-7bbf-4c59-a8e3-12dbb3271f0a", "booking_email": null, "booking_phone": "022-722-1234", "data_verified": false, "display_order": 0, "butler_service": false, "certifications": null, "deleted_reason": null, "description_en": null, "dining_options": null, "group_friendly": true, "internal_notes": "Lobby在26樓\n早餐26樓大廳餐廳\n7:00開始用餐（需餐券）\n\n冰箱內的飲料也是要付費的，\n咖啡機旁邊的礦泉水不用！\n膠囊咖啡機免費！\nWiFi密碼在打開電視右上方喔！\n\n抽菸室在26樓電梯旁\n飯店禁菸，煙蒂也請不要帶回房間\n房內抽菸會有高額罰金喔，請小心！\n\n<仙台站前商